var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"DAD_NPC_ANAP_NULL","text":{"KOREA":"증폭터널의 불안정성이 임계점에 다다르고 있어요.","JPN":"増幅トンネルの不安定性が臨界点に達しようとしています。","ENG":"The amplification tunnel's instability is approaching its critical threshold.","TWN":"增幅隧道的不穩定性已經接近臨界值。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_ANAP_GAP","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"DAD_NPC_ANAP_NULL","text":{"KOREA":"이대로라면 수 분 내에 붕괴될 겁니다.","JPN":"このままだと数分以内に崩壊します。","ENG":"At this rate, it will collapse within minutes.","TWN":"照這樣下去，幾分鐘內就會崩塌。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_ANAP_GAP","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"SEOSAENG_ATELIER_ANAP_GAP","text":{"KOREA":"곧 사람들이 필요한 물건을 가지고 돌아올 걸세.","JPN":"もうすぐ彼らが必要なものを持って帰ってくるであろう。","ENG":"They'll be back soon with what we need.","TWN":"他們很快就會帶著需要的東西回來。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_ANAP_GAP","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"SEOSAENG_ATELIER_ANAP_GAP","text":{"KOREA":"부디 그전까지, 안쪽에서 무사히 길을 터주길 바라는 수 밖에.","JPN":"どうかそれまで、あの中で無事道を切り開いてくれることを祈るしかあるまい。","ENG":"All we can do is hope they secure the path from the inside before then.","TWN":"只能希望在那之前，裡面的人能順利打通道路。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_ANAP_GAP","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"플라즈마 함포 최대 출력...!","JPN":"プラズマ艦砲、最大出力……！","ENG":"Plasma cannon at maximum output...!","TWN":"等離子艦炮最大輸出……！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_ENERGY_CHARGE"},{"id":"L10_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"...발사!","JPN":"……発射！","ENG":"...Fire!","TWN":"……發射！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_28"},{"id":"L15_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"장막이 약해졌어! 지금이야!","JPN":"幕が弱まってる！　今だ！","ENG":"The veil's weakened! Now!","TWN":"帷幕變弱了！趁現在！"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"...합!","JPN":"……はぁっ！","ENG":"...Hah!","TWN":"……喝！"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING_02"},{"id":"L20_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"하아... 하...","JPN":"はあ……はあ……","ENG":"*Huff...* *Huff...*","TWN":"呼……呼……"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L21_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"이렇게 많은 적수를 상대하는 건 처음이라... 쉽지 않네.","JPN":"これだけの数の敵を相手するのは初めてだから……すんなりとはいかないわね。","ENG":"Facing this many opponents at once... isn't easy.","TWN":"一次對付這麼多敵人……還真不輕鬆。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"응?","JPN":"あら？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"방금 그 빛줄기는... 반대편에서 온 건가?","JPN":"今の光は……反対側から？","ENG":"That beam of light just now... did it come from the other side?","TWN":"剛剛那道光……是來自另一邊嗎？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"틀림없어. 저 벽을 열려고 하는 거야.","JPN":"間違いないわ。あの壁を開けようとしている。","ENG":"No doubt about it. They're trying to open that wall.","TWN":"沒錯，他們在試圖打開那面牆。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"이쪽도 서둘러야겠...!","JPN":"こっちも急がな……！","ENG":"Then I need to hurry too–!","TWN":"我們也得快一點……！"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"큭?!","JPN":"くっ！？","ENG":"Ghk?!","TWN":"唔？！"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L31_1","type":"dialog","speaker":"MINISTRA_HORIZON_NULL_QM","text":{"KOREA":"넌, 지나갈 수 없다.","JPN":"お前は、通さない。","ENG":"You cannot pass.","TWN":"你，不能通過。"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MINISTRA_HORIZON_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"말하는 그림자? 어디서 나타난 거지?","JPN":"言葉を話すシャドウ？　どこから現れたの？","ENG":"A talking Shadow? Where did you come from?","TWN":"會說話的暗影？從哪裡冒出來的？"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MINISTRA_HORIZON_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"윽, 다리가...?","JPN":"うっ、足が……？","ENG":"Ngh, my leg...?","TWN":"呃……我的腿？"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MINISTRA_HORIZON_NULL_QM","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L34_1","type":"dialog","speaker":"MINISTRA_HORIZON_NULL_QM","text":{"KOREA":"기회를 엿보다가 발목을 찔렀어.","JPN":"隙を見て、足首を刺した。","ENG":"I waited for an opening and struck your ankle.","TWN":"我一直在等待機會，剛剛刺中了你的腳踝。"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MINISTRA_HORIZON_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"MINISTRA_HORIZON_NULL_QM","text":{"KOREA":"검에 의존하는 녀석에게 움직일 수 없다는 건, 치명적인 결함이지. 안 그래?","JPN":"剣に依存する者にとって、動けないということは致命的な欠陥だ。そうだろう？","ENG":"For someone who relies on a sword, being unable to move is a fatal flaw. Wouldn't you agree?","TWN":"對一個依賴劍的人來說，無法移動可是致命缺陷。不是嗎？"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MINISTRA_HORIZON_NULL_QM","face":"UNIT_LAUGH"}}}},{"id":"L36_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MINISTRA_HORIZON_NULL_QM","face":"UNIT_LAUGH"}}}},{"id":"L40_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"어떻게 된 거지? 분명 베었을 텐데?","JPN":"どういうこと？　確かに斬ったはずなのに。","ENG":"What's going on? I definitely cut it.","TWN":"怎麼回事？我明明砍到了。"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L41_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"잠깐이지만 그 너머에 사람 모습도 보였다고!","JPN":"一瞬だったけど、あの向こうに人の姿も見えたし！","ENG":"Just for a moment, but I saw someone on the other side!","TWN":"雖然只有一瞬間，但我看到後面有人影！"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"주시윤의 일격은 분명 효과가 있었어. 장막이 다시 순식간에 재생한 거야.","JPN":"アキヤマの一撃は確かに効果があった。幕がまた一瞬で再生したんだ。","ENG":"Shiyoon's strike definitely worked. The veil just regenerated instantly.","TWN":"周時雲那一擊確實有效，只是帷幕立刻又再生了。"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L43_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"지금보다 더 강한 공격이라면, 장막을 확실히 소멸시킬 수 있겠어.","JPN":"今よりももっと強い攻撃なら、もう少し長く開いているかもしれない。","ENG":"If the attack were stronger than before, it might stay open longer.","TWN":"如果是比現在更強力的攻擊，也許能維持更久。"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L45_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"...곤란하네요. 나름의 전력을 다한 일격이었는데 말이죠.","JPN":"……困りましたね。僕なりに全力で攻撃したんですが。","ENG":"...That's a problem. I already gave it everything I had.","TWN":"……那可糟了，我已經算使出全力了。"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"아무래도 순순히 열리진 않을 모양이군요.","JPN":"どうやら簡単には開いてくれなさそうです。","ENG":"It doesn't look like it'll open easily.","TWN":"看來對方不打算輕易讓我們過去。"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"마왕님이 힘을 좀 보태줄 수는 없을까?","JPN":"魔王様、もうちょっと頑張ってもらえない？","ENG":"Demon Lord, is there any way you could help out here?","TWN":"魔王能不能再多出點力啊？"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"글쎄요. 지금의 증폭터널의 상태는 무너지기 직전의 동굴 같은 거라서요.","JPN":"どうでしょう。今の増幅トンネルの状態は、崩れる寸前の洞窟のようなものなので。","ENG":"Hard to say. Right now, the amplification tunnel is like a cave on the verge of collapse.","TWN":"這個嘛……現在的增幅隧道就像隨時會崩塌的洞穴。"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"여기서 제 권능으로 충격을 주면 기껏 연결한 증폭터널이 붕괴되고 말 겁니다.","JPN":"ここで僕の権能で衝撃を与えると、せっかく繋げた増幅トンネルが崩壊してしまいます。","ENG":"If I strike it with my power here, the amplification tunnel we barely connected will collapse.","TWN":"如果在這裡使用我的權能施加衝擊，好不容易連接起來的隧道就會崩潰。"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"시윤 군의 검처럼, 차원계면에 부담을 주지 않고 공간만을 베어내는 게 지금으로선 유력한 해결책이죠.","JPN":"シリュウ君の剣のように、次元界面に負担をかけずに空間だけを斬るのが今としては有効な解決方法だと思います。","ENG":"For now, the most reliable solution is something like Shiyoon's sword, cutting only space itself without placing strain on the dimension surface.","TWN":"像時雲的劍那樣，不對次元界面造成負擔、只劈開空間，才是目前最好的方法。"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"그치만 장막을 베는 속도랑 재생 속도가 같으면 의미가 없잖아.","JPN":"でも、幕を斬る速度と再生速度が一緒だと意味がないじゃん。","ENG":"But if the cutting speed and regeneration speed are the same, that won't mean anything.","TWN":"但如果切開的速度跟再生速度一樣快，那也沒意義啊。"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_DESPAIR"},"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"시윤이 같은 능력자를 둘로 복제하는 게 아닌 이상에야...","JPN":"シリュウみたいな能力者を複製しないかぎり……","ENG":"Unless we can somehow duplicate someone with Shiyoon's ability...","TWN":"除非把時雲這種能力者複製成兩個……"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_DESPAIR"},"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"가능합니다.","JPN":"可能ですよ。","ENG":"It's possible.","TWN":"這可行。"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_DESPAIR"},"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"진짜? 마왕님의 힘으로 복제할 수 있는 거야?!","JPN":"本当？　魔王様の力で複製できるの！？","ENG":"Really? You can duplicate him with your power, Demon Lord?!","TWN":"真的嗎？可以用魔王的力量複製嗎？！"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_SURPRISE"},"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"저에게 그런 능력은 없습니다만...","JPN":"僕にそんな能力はないですが……","ENG":"I don't have that kind of ability...","TWN":"雖然我沒有那種能力……"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_SURPRISE"},"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"두 배로 더 열심히 노력하면 어떻게든 되지 않겠습니까?","JPN":"2倍頑張れば、何とかなるのではないでしょうか？","ENG":"But if we try twice as hard, shouldn't that be enough?","TWN":"不過，只要加倍努力，不就行了嗎？"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_SURPRISE"},"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"뭐야 그게...?","JPN":"何それ……？","ENG":"What kind of answer is that...?","TWN":"那算什麼啊……？"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_DESPAIR"},"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"...100% 공감은 못하겠지만, 어느 정도 일리가 있는 말씀이네요.","JPN":"……100％共感はできないですけど、一理ありますね。","ENG":"...I can't fully agree, but there's some logic to what you're saying.","TWN":"……雖然我無法100%認同，但多少有點道理。"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"달리 방법이 없다면, 그게 통할 때까지 되풀이해보는 거죠.","JPN":"他に方法がないなら、それが通じるまで繰り返すまでです。","ENG":"If there's no other way, then we'll just keep trying until it works.","TWN":"既然沒有其他方法，就只能一直試到成功為止。"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"헉... 헉...","JPN":"はっ……はぁ……","ENG":"*Huff...* *Huff...*","TWN":"呼……呼……"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MINISTRA_HORIZON_NULL_QM","text":{"KOREA":"지금까지 제법 잘 막고 있다만, 한낱 인간일 뿐인 네겐 곧 한계가 올 거다.","JPN":"今までよく受け止めているが、たかが人間であるお前にはもうすぐ限界が来るだろう。","ENG":"You've done fairly well holding out this long, but you're still only human. Your limit is approaching.","TWN":"到目前為止你確實撐得不錯。但你終究只是個人類，很快就會到極限。"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MINISTRA_HORIZON_NULL_QM","face":"UNIT_LAUGH"}}}},{"id":"L16_1","type":"dialog","speaker":"MINISTRA_HORIZON_NULL_QM","text":{"KOREA":"막는 것 밖에 못할 바엔, 일찌감치 포기하고 편해지는 게 좋지 않겠니?","JPN":"受け止めることしかできないのなら、早めに諦めて楽になったらどうだ？","ENG":"If all you can do is defend, wouldn't it be better to give up early and make things easier for yourself?","TWN":"既然只能防守，不如早點放棄，讓自己輕鬆一點吧？"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MINISTRA_HORIZON_NULL_QM","face":"UNIT_LAUGH"}}}},{"id":"L17_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"후후... 막는 것 밖에 못하다뇨?","JPN":"ふふ……受け止めることしかできない？","ENG":"Haha... All I can do is defend?","TWN":"呵呵……誰說我只能防守？"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MINISTRA_HORIZON_NULL_QM","face":"UNIT_LAUGH"}}}},{"id":"L18_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"공격할 틈을 주셔야... 공격을 하죠.","JPN":"攻撃する隙をくだされば……攻撃しますよ。","ENG":"You need to give me an opening... so I can attack.","TWN":"你得先給我……攻擊的機會才行啊？"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MINISTRA_HORIZON_NULL_QM","face":"UNIT_LAUGH"}}}},{"id":"L19_1","type":"dialog","speaker":"MINISTRA_HORIZON_NULL_QM","text":{"KOREA":"흥, 움직이지도 못하는 주제에 입만 살았군.","JPN":"ふん、動けないくせに口だけは達者だな。","ENG":"Hmph. You can't even move, yet you still talk big.","TWN":"哼，連動都動不了，還在嘴硬。"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MINISTRA_HORIZON_NULL_QM","face":"UNIT_SERIOUS"}}}},{"id":"L20_1","type":"dialog","speaker":"MINISTRA_HORIZON_NULL_QM","text":{"KOREA":"...끝이다!","JPN":"……これで終わりだ！","ENG":"...Let's end this!","TWN":"……結束了！"},"stage":{"bg":"MIND","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MINISTRA_HORIZON_NULL_QM","face":"UNIT_SERIOUS"}}},"sfx":"FX_COMBAT_MONSTER_MINISTRA_PHASECHANGE"},{"id":"L24_1","type":"dialog","speaker":"MINISTRA_HORIZON_NULL_QM","text":{"KOREA":"뭣이?","JPN":"何？","ENG":"Huh?","TWN":"什麼？！"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MINISTRA_HORIZON_NULL_QM","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINISTRA_HORIZON_NULL_QM","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"이번엔 늦지 않으셨네요.","JPN":"今回は間に合いましたね。","ENG":"This time, you weren't late.","TWN":"這次終於沒遲到呢。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MINISTRA_HORIZON_NULL_QM","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"스승님.","JPN":"師匠。","ENG":"Master.","TWN":"師父。"},"stage":{"bg":"MIND","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MINISTRA_HORIZON_NULL_QM","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"...여기까지 오느라 고생했다, 연화.","JPN":"……ここまでよくやった、レンカ。","ENG":"...You've done well making it this far, Yeonhwa.","TWN":"……辛苦了，蓮華。"},"stage":{"bg":"MIND","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MINISTRA_HORIZON_NULL_QM","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"가르친 보람이 있어.","JPN":"教えた甲斐があったな。","ENG":"I'm proud of you.","TWN":"真是沒有白教你。"},"stage":{"bg":"MIND","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"MINISTRA_HORIZON_NULL_QM","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"와아...","JPN":"わあ……","ENG":"Wow...","TWN":"哇……"},"stage":{"bg":"MIND","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"MINISTRA_HORIZON_NULL_QM","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"스승님께서 절 그렇게 칭찬하시는 거, 태어나서 처음 들어요.","JPN":"師匠が私をそんなに褒めてくれるなんて、生まれて初めてです。","ENG":"This is the first time I've ever heard you praise me like that, Master.","TWN":"我還是第一次聽到師父這樣誇我呢。"},"stage":{"bg":"MIND","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"MINISTRA_HORIZON_NULL_QM","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"미래에도 스승님은 여전히 좋은 분이네요.","JPN":"未来でも師匠は相変わらず優しい方ですね。","ENG":"Even in the future, you're still the same wonderful person.","TWN":"就算是在未來，師父還是這麼好。"},"stage":{"bg":"MIND","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"MINISTRA_HORIZON_NULL_QM","face":"UNIT_SURPRISE"}}}},{"id":"L35_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MIND","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MINISTRA_HORIZON_NULL_QM","face":"UNIT_SURPRISE"}}}},{"id":"L36_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"지금부터 방어는 내게 맡기고, 공격에 전념하도록.","JPN":"これから防御は私に任せて、攻撃に専念しろ。","ENG":"From here on, leave the defending to me and focus on attacking.","TWN":"接下來防禦交給我，你專心攻擊。"},"stage":{"bg":"MIND","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"MINISTRA_HORIZON_NULL_QM","face":"UNIT_SURPRISE"}}}},{"id":"L37_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"내가 직접 힘을 쓸 정도로 터널의 상태가 안정적이진 않으니 말이야.","JPN":"私が直接力を使えるほど、トンネルの状態が安定していないからな。","ENG":"The tunnel isn't stable enough for me to use my power directly.","TWN":"隧道的狀態還不穩定，不適合我親自動用力量。"},"stage":{"bg":"MIND","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"MINISTRA_HORIZON_NULL_QM","face":"UNIT_SURPRISE"}}}},{"id":"L38_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"네, 알겠습니다.","JPN":"はい、分かりました。","ENG":"Yes, understood.","TWN":"是，我知道了。"},"stage":{"bg":"MIND","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MINISTRA_HORIZON_NULL_QM","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"MINISTRA_HORIZON_NULL_QM","text":{"KOREA":"흥, 달리지도 못하는 검사에게 공격을 맡기다니. 내가 그리 쉽게...","JPN":"ふん、走れない剣士に攻撃を任せるとは。私がそう簡単に……","ENG":"Hmph. Entrusting the attack to a swordsman who can't even run? Do you really think I'll go down that eas–","TWN":"哼，把攻擊交給一個連跑都跑不了的劍士？我可沒那麼容易……"},"stage":{"bg":"MIND","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_HORIZON_NULL_QM","face":"UNIT_HATE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MINISTRA_HORIZON_NULL_QM","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_HORIZON_NULL_QM","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_SWORD_SLASH_BIG_10"},{"id":"L45_1","type":"dialog","speaker":"MINISTRA_HORIZON_NULL_QM","text":{"KOREA":"...말도, 안돼.","JPN":"……そんな、バカな。","ENG":"...Impossible.","TWN":"……不可能。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_HORIZON_NULL_QM","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MINISTRA_HORIZON_NULL_QM","text":{"KOREA":"그 먼 거리에서... 움직이지도 않고, 날 벨 수 있다고?","JPN":"その距離で……動きもせず私を斬れるだと？","ENG":"From that distance... without even moving, you can still cut me?","TWN":"隔著那麼遠的距離……連動都沒動，就能砍到我？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_HORIZON_NULL_QM","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"그럼요.","JPN":"もちろんです。","ENG":"Of course.","TWN":"當然囉。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"총알 날아다니는 세상에 칼로 먹고 사는 게, 쉬운 일은 아니랍니다?","JPN":"銃弾が飛び交うこの世界で、剣で生計を立てていくことがそう簡単だとでも？","ENG":"In a world where bullets fly everywhere, making a living with a sword isn't exactly easy, you know.","TWN":"在子彈滿天飛的世界裡，靠劍吃飯可不是件容易的事唷？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"이걸로 골칫거리 하난 치웠군.","JPN":"これで邪魔者は1人片付いたか。","ENG":"That takes care of one troublesome opponent.","TWN":"這下總算解決一個麻煩了。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"지금부터 네 할 일은 네가 알고 있겠지.","JPN":"今からお前がやるべきことは分かっているな。","ENG":"You know what you need to do next.","TWN":"接下來該做什麼，你應該很清楚。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"인형들은 내게 맡겨라.","JPN":"人形たちは私に任せろ。","ENG":"Leave the dolls to me.","TWN":"人偶交給我。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_MISSILE_RELOAD"},{"id":"L4_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"그럼, 뒤는 부탁 드릴게요.","JPN":"では、後はお願いします。","ENG":"Then I'll leave the rest to you.","TWN":"那後面就拜託你了。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"헉... 헉...","JPN":"はっ……はぁ……","ENG":"*Huff...* *Huff...*","TWN":"呼……呼……"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_BLADE_BIG_03"},{"id":"L9_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"...이제 그만 둬.","JPN":"……もうやめなよ。","ENG":"...Stop already.","TWN":"……停手吧。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"몇 번을 베어도 원래대로 돌아올 뿐, 이대론 지쳐서 쓰러질 뿐이야.","JPN":"何度斬っても元どおりになるだけだし、このままだと疲れて倒れちゃうよ。","ENG":"No matter how many times you cut it, it just returns to normal. At this rate, you'll collapse from exhaustion.","TWN":"不管砍幾次都會恢復原狀，再這樣下去你只會力竭倒下。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"가능성이 없다고.","JPN":"可能性がないって。","ENG":"There's no chance.","TWN":"這是不可能的。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"...아뇨.","JPN":"……いいえ。","ENG":"...No.","TWN":"……不是。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"애초에 가능성이라는 건, 성공하기 전까지 아무런 의미가 없어요-","JPN":"そもそも可能性というものは、成功するまで何の意味もないんです……","ENG":"To begin with, possibilities mean nothing until you succeed...","TWN":"所謂的可能性，在成功之前本來就沒有任何意義。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"-포기하는 순간, 그 일말의 가능성조차 사라져버리고 마니까요.","JPN":"諦めた瞬間、そのわずかな可能性でさえ消えてしまうんですから。","ENG":"And the moment you give up, even that faint possibility disappears.","TWN":"一旦放棄—那僅存的一點可能性也會消失。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"하지만 포기하지 않는다면-","JPN":"でも諦めないかぎり……","ENG":"But if you don't give up...","TWN":"但只要不放棄—"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"-가능성은 언제나...!","JPN":"可能性はいつでも……！","ENG":"Then possibilities will always...!","TWN":"—可能性就永遠都在……！"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"음?","JPN":"ん？","ENG":"Hm?","TWN":"嗯？"},"stage":{"bg":"MIND","bgm":"THEMA_CA_CLOUD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"방금... 휘두르기도 전에 공간이 갈라진 것 같은데?","JPN":"今……振り回す前に空間が裂けたみたいだけど。","ENG":"Just now... didn't the space split open before he even swung?","TWN":"剛才……好像還沒揮劍，空間就裂開了？"},"stage":{"bg":"MIND","bgm":"THEMA_CA_CLOUD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MIND","bgm":"THEMA_CA_CLOUD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"...가능성은 언제나, 존재하는 거라고요.","JPN":"……可能性はいつでも、存在するんですよ。","ENG":"...Possibilities always exist.","TWN":"……可能性，一直都存在。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_CLOUD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L27_1","type":"narration","speaker":null,"text":{"KOREA":"...그래.","JPN":"……ああ。","ENG":"...Right.","TWN":"……嗯。"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_CLOUD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"narration","speaker":null,"text":{"KOREA":"마음 향하는 곳에 길이 있는 법이니까.","JPN":"心惹かれる場所に道はあるものだからな。","ENG":"Because where the heart leads, a path will always follow.","TWN":"心之所向，自會有路。"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_CLOUD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"장막이...","JPN":"幕が……","ENG":"The veil...","TWN":"帷幕……"},"stage":{"bg":"MIND","bgm":"THEMA_CA_CLOUD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_COMBAT_ALL_ENERGY_ATTACK_BIG_20"},{"id":"L32_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"...갈라지고 있어.","JPN":"……裂けてる。本当に？","ENG":"...it's splitting. I can't believe it.","TWN":"……裂開了。真的嗎？"},"stage":{"bg":"MIND","bgm":"THEMA_CA_CLOUD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L34_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MIND","bgm":"THEMA_CA_CLOUD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"꺄앗, 눈 부셔! 갑자기 무슨 빛줄기지?!","JPN":"きゃあっ、眩しい！　いきなり何の光！？","ENG":"Ahh, it's so bright! What's that beam of light all of a sudden?!","TWN":"呀！好刺眼！怎麼會突然有光？！"},"stage":{"bg":"MIND","bgm":"THEMA_CA_CLOUD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"...파노라마의 반사광이군요. 달님 팀에서 회수에 성공했나 보네요.","JPN":"……パノラマの反射光ですね。お月様チームが回収に成功したのでしょう。","ENG":"...That's the reflected light from Panorama. It looks like Team Moon succeeded in retrieving it.","TWN":"……是全景的反射光，看來月亮隊成功回收了。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_CLOUD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"양쪽 출입로가 파노라마의 영향을 받기 시작했으니, 아이린 양이 곧 증폭터널을 복제할 겁니다.","JPN":"両側の出入口がパノラマの影響を受け始めていますから、アイリーンさんがもうすぐ増幅トンネルを複製するはずです。","ENG":"Now that both entrances are beginning to fall under Panorama's influence, Irene will soon duplicate the amplification tunnel.","TWN":"兩側入口已經開始受到全景影響，艾琳很快就會複製增幅隧道。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_CLOUD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"오, 무사히 통신이 회복됐구만!","JPN":"おお、無事通信が回復したね！","ENG":"Oh, comms are back online!","TWN":"喔，通訊恢復了！"},"stage":{"bg":"MIND","bgm":"THEMA_CA_CLOUD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L41_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"증폭터널이 정상적으로 작동하기 시작한 걸 보니, 녀석의 군세를 몰아내는데 성공한 모양이구나.","JPN":"増幅トンネルが正常に作動してるところを見るに、やつの軍勢を追い払うことに成功したようだね。","ENG":"Since the amplification tunnel has started operating normally again, it looks like you succeeded in driving back their forces.","TWN":"既然增幅隧道開始正常運作，看來成功擊退那傢伙的軍勢了。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_CLOUD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"지금부터 우린 예정대로 우물에 과부하를 걸어 초광역터널을 열 것이다. 그럼 제 역할을 다한 증폭터널은 곧 자연스럽게 닫히겠지.","JPN":"今から私たちは予定どおりイドに過負荷をかけ、超広域トンネルを開く。そうなれば役割を果たした増幅トンネルはまもなく自然に閉まるはずだ。","ENG":"From here on, we'll proceed as planned and overload the Well to open a hyperwide tunnel. Once that happens, the amplification tunnel will naturally close after fulfilling its role.","TWN":"接下來我們會按照計畫讓井超載、開啟超廣域隧道。到時完成任務的增幅隧道就會自然關閉。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_CLOUD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"그러니 너희는 현실로 부상할 준비를 해둬라. 뭐, 준비라고 해봐야 가만히 있으면 동앗줄이 알아서 다 해결해주겠지만?","JPN":"だからあなたたちは現実に浮上する準備をしておいて。まあ、準備といっても、じっとしてれば縄がすべて解決してくれるけど。","ENG":"So get ready to surface back into reality. Though honestly, there's nothing to prepare. The Straw Rope will take care of everything on its own.","TWN":"所以你們準備好浮出現實吧。不過說是準備，其實什麼都不用做，繩索自然會把你們拉上來。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_CLOUD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"와아...","JPN":"わあ……","ENG":"Wow...","TWN":"哇……"},"stage":{"bg":"MIND","bgm":"THEMA_CA_CLOUD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"정말 대단하네! 포기만 안하면 된다는 근성론이 진짜 통하는 거였구나! 다시 봤어!","JPN":"本当にすごいね！　諦めなければうまく行くって根性論が本当に通じるんだ！　見直したよ！","ENG":"That's amazing! So that whole \\"just don't give up\\" mindset actually worked! I'm impressed!","TWN":"太厲害了！原來只要不放棄就會成功的熱血理論真的有用！我對你改觀了！"},"stage":{"bg":"MIND","bgm":"THEMA_CA_CLOUD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_LAUGH"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"...수고 많았어요, 시윤 군.","JPN":"……お疲れ様でした、シリュウ君。","ENG":"...You did well, Shiyoon.","TWN":"……辛苦了，時雲。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_CLOUD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"이제 돌아갑시다.","JPN":"この辺で戻りましょう。","ENG":"Now let's head back.","TWN":"我們回去吧。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_CLOUD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"문제가 해결됐으니, 이제 타기리온을 만나러 가야죠.","JPN":"問題が解決しましたので、今度はタギリオンに会いに行かなくては。","ENG":"The problem's been resolved. It's time we went to meet Thagirion.","TWN":"既然問題解決了，接下來該去見塔基里翁了。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_CLOUD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MIND","bgm":"THEMA_CA_CLOUD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"작전은 성공이군.","JPN":"作戦は成功したな。","ENG":"The operation was a success.","TWN":"作戰成功。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_CLOUD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"이제 곧 모든 게 정상으로 돌아갈 거다.","JPN":"もうすぐすべてが元通りに戻るだろう。","ENG":"Soon, everything will return to normal.","TWN":"一切很快就會恢復正常。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_CLOUD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"휴우...","JPN":"ふう……","ENG":"Phew...","TWN":"呼……"},"stage":{"bg":"MIND","bgm":"THEMA_CA_CLOUD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"아! 그러고 보니 미나와 노엘은 무사한가요?","JPN":"あ！　そういえばミナとノエルは無事ですか？","ENG":"Oh! Come to think of it, are Mina and Noelle safe?","TWN":"啊！話說米娜和洛艾兒沒事吧？"},"stage":{"bg":"MIND","bgm":"THEMA_CA_CLOUD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"그런 꼴로 다른 사람 걱정부터 하는 거냐?","JPN":"その状態で人の心配をしている場合か？","ENG":"Look at the state you're in, and you're worried about others first?","TWN":"你都傷成這樣了，還先擔心別人？"},"stage":{"bg":"MIND","bgm":"THEMA_CA_CLOUD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"무사하니 걱정 마라. 네 발목의 상처도 터널이 닫히는 대로 멀쩡히 돌아올 거야.","JPN":"無事だから心配するな。お前の足首の怪我も、トンネルが閉じればすぐ治るだろう。","ENG":"They're safe, so don't worry. Once the tunnel closes, the injury to your ankle will return to normal as well.","TWN":"放心吧，她們沒事。你的腳踝傷等隧道關閉後也會復原。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_CLOUD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"후후, 다행이네요.","JPN":"ふふ、よかったです。","ENG":"Haha, that's a relief.","TWN":"呵呵，太好了。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_CLOUD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"우린 이만 돌아가마.","JPN":"私たちももう帰ることにする。","ENG":"We'll be heading back now.","TWN":"我們先回去了。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_CLOUD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L11_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"잘 지내란 말씀은 안 해주시나요?","JPN":"達者でいろとは言ってくださらないんですか？","ENG":"Won't you tell me to stay safe?","TWN":"不說句保重嗎？"},"stage":{"bg":"MIND","bgm":"THEMA_CA_CLOUD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MIND","bgm":"THEMA_CA_CLOUD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"나에겐, 너한테 그런 말을 할 자격이 없어.","JPN":"私には、お前にそんなことを言う資格がない。","ENG":"I don't have the right to say something like that to you.","TWN":"我沒有資格對你說那種話。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_CLOUD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"역시... 용혈때문인 거죠?","JPN":"やはり……龍血のせいなんですね？","ENG":"Just as I thought... It's because of the Dragon Blood, isn't it?","TWN":"果然……是因為龍血吧？"},"stage":{"bg":"MIND","bgm":"THEMA_CA_CLOUD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"너...?","JPN":"お前……？","ENG":"You...?","TWN":"你……？"},"stage":{"bg":"MIND","bgm":"THEMA_CA_CLOUD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"그런 표정을 지으실까 봐 말은 하지 않았지만, 늘 생각하고 있었어요.","JPN":"そういう顔をされると思って言いませんでしたが、いつも考えてはいたんです。","ENG":"I didn't say anything because I thought you might make that kind of expression, but I've always known.","TWN":"我就怕師父會露出那種表情，所以一直沒說。但我一直都在想著這件事。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_CLOUD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"제가 더는 버티지 못하게 되면, 스승님께서 막아주시기로 약속했으니까요.","JPN":"私が耐えられなくなったら、師匠が止めてくれる約束でしたから。","ENG":"If the day comes when I can't hold on anymore, you promised you would stop me.","TWN":"如果有一天我撐不下去了，師父答應過會阻止我。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_CLOUD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MIND","bgm":"THEMA_CA_CLOUD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"연화, 난 너한테...","JPN":"レンカ、私はお前に……","ENG":"Yeonhwa, I'm–","TWN":"蓮華，我對你……"},"stage":{"bg":"MIND","bgm":"THEMA_CA_CLOUD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"미안하다는 말은 스승님한테 어울리지 않아요.","JPN":"謝罪の言葉は師匠に似合いませんよ。","ENG":"\\"Sorry\\" doesn't suit you, Master.","TWN":"對不起這句話，不適合師父說。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_CLOUD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"제자에게 갖는 죄책감이 아니라도, 앞으로 많은 걸 짊어지고 나가실 분이잖아요?","JPN":"弟子に感じる罪悪感以外にも、これからたくさんのものを背負わないといけない方ですから。","ENG":"Even without guilt toward your apprentice, you're someone who still has many things to carry forward.","TWN":"就算不是對弟子的愧疚，您也是未來要背負許多責任的人不是嗎？"},"stage":{"bg":"MIND","bgm":"THEMA_CA_CLOUD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"전 말이죠. 제게 주어진 시간 동안 최선을 다해서 행복할 거에요.","JPN":"私はね。自分に与えられた時間の中で、全力で幸せになります。","ENG":"As for me, I'm going to do my best to be happy for the time I've been given.","TWN":"我啊，在被賦予的時間內，會盡全力活得幸福。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_CLOUD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"그래서 마지막에 그 어떤 후회도 남기지 않기로, 제 자신과 약속했거든요.","JPN":"それで、最後にどんな後悔も残さないって、自分自身と約束したんです。","ENG":"So I made a promise to myself not to leave behind any regrets at the end.","TWN":"我已經跟自己約好，在最後不留下任何後悔。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_CLOUD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"그러니까- 저 때문에 그런 표정 짓지 마세요.","JPN":"だから……私なんかのためにそんな顔しないでください。","ENG":"So... please don't make that kind of expression because of me.","TWN":"所以—不要因為我露出那種表情。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_CLOUD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"이런 힘든 일도 해내는 멋진 제자를 키워낸, 멋진 스승님다운 표정을 보여주세요.","JPN":"こんな大変なことだってやり遂げる立派な弟子を育てた、立派な師匠らしい顔をしてください。","ENG":"Show me the expression of the wonderful master who raised such a wonderful apprentice capable of overcoming even hardships like this.","TWN":"請露出那種培養出能完成這麼困難任務的優秀弟子，那種了不起的師父該有的表情。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_CLOUD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MIND","bgm":"THEMA_CA_CLOUD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"...그래.","JPN":"……わかった。","ENG":"...All right.","TWN":"……嗯。"},"stage":{"bg":"MIND","bgm":"THEMA_CA_CLOUD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"아 참.","JPN":"あ、そうでした。","ENG":"Oh, right.","TWN":"啊，對了。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"그러고 보니 저 멀리서, 아주 잘생긴 소년을 본 것...","JPN":"そういえば遠くに、とてもカッコいい少年を見たような……","ENG":"Come to think of it, earlier I saw a very handsome boy...","TWN":"話說，我剛才在遠處……"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"...같은데-","JPN":"……気が……","ENG":"...in the distance...","TWN":"好像看到一個非常帥氣的少年－"},"stage":{"bg":"MS_1602_1","bgm":"THE_WAY_THE_DECISION","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L34_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MS_1602_1","bgm":"THE_WAY_THE_DECISION","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L35_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MS_1602_1","bgm":"THE_WAY_THE_DECISION","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L38_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>경보. 증폭터널이 유지 한계에 도달했습니다.</color>","JPN":"<color=#ffd34c>警報。増幅トンネルが維持限界に達しました。</color>","ENG":"<color=#ffd34c>Warning. The amplification tunnel has reached its maintenance limit.</color>","TWN":"<color=#ffd34c>警報。增幅隧道已達維持極限。</color>"},"stage":{"bg":"MS_1602_1","bgm":"THE_WAY_THE_DECISION","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_SIREN"},{"id":"L39_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>약 40초 후, 증폭터널이 폐쇄되며 체류 중인 인원은 진입한 출입로를 통해 배출됩니다.</color>","JPN":"<color=#ffd34c>約40秒後、増幅トンネルが封鎖され、中に残っている人員は進入した出入口から排出されます。</color>","ENG":"<color=#ffd34c>In approximately 40 seconds, the amplification tunnel will close, and all remaining personnel will be discharged through their entry points.</color>","TWN":"<color=#ffd34c>約40秒後，增幅隧道將關閉，停留人員會自進入的入口排出。</color>"},"stage":{"bg":"MS_1602_1","bgm":"THE_WAY_THE_DECISION","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"...널 아주 쏙 빼어 닮았지.","JPN":"……お前によく似てるだろう？","ENG":"...He takes after you exactly.","TWN":"……和你長得一模一樣。"},"stage":{"bg":"MS_1602_1","bgm":"THE_WAY_THE_DECISION","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"아주 많은 시련을 거쳤음에도... 그걸 모두 딛고 일어설 만큼 강인한 성정마저 닮았어.","JPN":"たくさんの試練を経験しても……それをすべて乗り越えられるほど強いところまでそっくりだ。","ENG":"Even after going through so many trials... he has the same strength of character to overcome all of them.","TWN":"即使經歷了那麼多試煉……仍然能重新站起來的堅強性格，也和你一樣。"},"stage":{"bg":"MS_1602_1","bgm":"THE_WAY_THE_DECISION","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"그러니, 너무 걱정하진 마라.","JPN":"だから、あまり心配するな。","ENG":"So don't worry too much.","TWN":"所以，不用太擔心了。"},"stage":{"bg":"MS_1602_1","bgm":"THE_WAY_THE_DECISION","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MS_1602_1","bgm":"THE_WAY_THE_DECISION","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"그러네요.","JPN":"そうですね。","ENG":"You're right.","TWN":"是啊。"},"stage":{"bg":"MS_1602_1","bgm":"THE_WAY_THE_DECISION","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"실은 제가 꿈꾸는 미래가... 남겨질 누군가의 삶을 원망으로 망가뜨리진 않을까, 많이 걱정했었거든요.","JPN":"実は私が夢見ている未来が……残された誰かの人生を憎しみで台無しにしてしまうのではないかと、心配していたんです。","ENG":"Actually, I was worried that the future I dream of... might end up ruining the life of someone left behind with resentment.","TWN":"其實我一直很擔心……我夢想的未來，會不會讓留下來的人因怨恨而毀掉人生。"},"stage":{"bg":"MS_1602_1","bgm":"THE_WAY_THE_DECISION","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"앞으로의 저는... 세상에서 제일 쓸 데 없는 걱정을 달고 살게 되겠네요.","JPN":"これからの私は……世界で一番無駄な心配をすることになるでしょうね。","ENG":"From now on... I guess I'll be carrying around the most unnecessary worry in the world.","TWN":"看來以後的我……會帶著世界上最沒意義的擔心生活著。"},"stage":{"bg":"MS_1602_1","bgm":"THE_WAY_THE_DECISION","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"...그래. 아주 쓸데없는 걱정이 되겠구나.","JPN":"……そうだな。まったく無駄な心配だ。","ENG":"...Yes. It really will become a very unnecessary worry.","TWN":"……是啊，那會變成非常沒意義的擔心呢。"},"stage":{"bg":"MS_1602_1","bgm":"THE_WAY_THE_DECISION","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"후훗...","JPN":"ふふっ……","ENG":"Haha...","TWN":"呵呵……"},"stage":{"bg":"MS_1602_1","bgm":"THE_WAY_THE_DECISION","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"그렇게 빤히 보기만 하지 말고, 손이라도 흔들어주는 건 어떠냐?","JPN":"そうじっと見てばかりいないで、手でも振ってやったらどうだ？","ENG":"Instead of just staring like that, how about giving him a wave?","TWN":"別只是一直盯著看，至少揮揮手吧？"},"stage":{"bg":"MS_1602_1","bgm":"THE_WAY_THE_DECISION","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MS_1602_1","bgm":"THE_WAY_THE_DECISION","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"일부러 절 만나러 오지 않은 걸 텐데... 그래도 괜찮을까요?","JPN":"わざと私に会いに来なかったはずなのに……いいんでしょうか？","ENG":"He probably didn't come all this way to meet me on purpose... but would it still be all right?","TWN":"他明明不是特地來見我的……這樣真的沒關係嗎？"},"stage":{"bg":"MS_1602_1","bgm":"THE_WAY_THE_DECISION","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"저 녀석은 겁이 났을 뿐인 거다. 과거의 널 만나도 아는 척 할 수 없고. 행여나 낯선 취급을 받을까 봐 두려웠던 거지.","JPN":"あいつは怖かっただけだろう。過去のお前に会って声をかけることもできないし、もしかしたら余所余所しい態度を取られるかもしれないと思って。","ENG":"He was just scared. Even if he met the you from the past, he wouldn't be able to acknowledge you. He was afraid you might treat him like a stranger.","TWN":"那傢伙只是害怕而已。就算遇到過去的你也不能相認，怕被當成陌生人。"},"stage":{"bg":"MS_1602_1","bgm":"THE_WAY_THE_DECISION","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"의연하긴 해도, 그런 면에선 아직 어린애니까.","JPN":"毅然としていても、そういうところはまだ子どもだからな。","ENG":"He may be composed, but in that regard he's still just a child.","TWN":"再怎麼沉著，在那方面終究還是個孩子。"},"stage":{"bg":"MS_1602_1","bgm":"THE_WAY_THE_DECISION","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"에이, 어린애라고요? 저렇게 듬직한데?","JPN":"もう、子どもだなんて。あんなにしっかりしているのに？","ENG":"Oh come on, a child? When he looks that reliable?","TWN":"欸，什麼孩子？明明看起來那麼可靠。"},"stage":{"bg":"MS_1602_1","bgm":"THE_WAY_THE_DECISION","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"강요하는 건 아니니, 네가 원하는 대로 해.","JPN":"無理強いはしない。お前のいいようにすればいい。","ENG":"I'm not forcing you. Do as you wish.","TWN":"我不是強迫你，你想怎麼做就怎麼做。"},"stage":{"bg":"MS_1602_1","bgm":"THE_WAY_THE_DECISION","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MS_1602_1","bgm":"THE_WAY_THE_DECISION","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MS_1602_1","bgm":"THE_WAY_THE_DECISION","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"}}}},{"id":"L8_1","type":"narration","speaker":null,"text":{"KOREA":"이쪽을 바라보며 웃는다.","JPN":"こちらを見て笑っている。","ENG":"She's looking this way and smiling.","TWN":"他微笑著望向這裡。"},"stage":{"bg":"MS_1602_1","bgm":"THE_WAY_THE_DECISION","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"narration","speaker":null,"text":{"KOREA":"멀어서 목소리는 들리지 않는다.","JPN":"遠くて声は聞こえない。","ENG":"She's too far away for me to hear her voice.","TWN":"距離太遠，聽不見聲音。"},"stage":{"bg":"MS_1602_1","bgm":"THE_WAY_THE_DECISION","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"}}}},{"id":"L10_1","type":"narration","speaker":null,"text":{"KOREA":"대신 또렷한 입 모양으로, 한 자 한 자 메시지를 전하고 있었다.","JPN":"その代わり、はっきりとした口の形で、一言一言メッセージを伝えていた。","ENG":"Instead, with clear lip movements, she was delivering her message one word at a time.","TWN":"但嘴型清楚地一字一字傳達著訊息。"},"stage":{"bg":"MS_1602_1","bgm":"THE_WAY_THE_DECISION","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"}}}},{"id":"L11_1","type":"narration","speaker":null,"text":{"KOREA":"안녕 멋진 소년.","JPN":"こんにちは、カッコいい少年。","ENG":"Hello, handsome.","TWN":"你好，帥氣的少年。"},"stage":{"bg":"MS_1602_1","bgm":"THE_WAY_THE_DECISION","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"narration","speaker":null,"text":{"KOREA":"날 만나러 와줘서 고마워.","JPN":"私に会いに来てくれてありがとう。","ENG":"Thank you for coming to see me.","TWN":"謝謝你來見我。"},"stage":{"bg":"MS_1602_1","bgm":"THE_WAY_THE_DECISION","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"narration","speaker":null,"text":{"KOREA":"그것은 먼 미래의 내게 고하는 작별이자,","JPN":"それは遠い未来の僕に告げるお別れで、","ENG":"That must have been a farewell addressed to me in the distant future,","TWN":"那既是對遙遠未來自己的告別，"},"stage":{"bg":"BLACK","bgm":"THE_WAY_THE_DECISION","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"narration","speaker":null,"text":{"KOREA":"가까운 미래의 내게 보내는 인사였을 것이다.","JPN":"近い未来の僕に送る挨拶だったのだろう。","ENG":"and a greeting sent to me in the near future.","TWN":"也是對不久後的自己送上的問候。"},"stage":{"bg":"BLACK","bgm":"THE_WAY_THE_DECISION","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"휴우, 마지막엔 아슬아슬했어.","JPN":"ふう、最後は危なかったよ。","ENG":"Phew, that got pretty close at the end.","TWN":"呼……最後真的有點驚險。"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"달님 팀도 고생 많았어요.","JPN":"お月様チームもお疲れ様でした。","ENG":"Team Moon, you all did great too.","TWN":"月亮隊也辛苦了。"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"선배도 무사했구나. 다행이야.","JPN":"先輩も無事だったんだね。よかった。","ENG":"You made it back safely too, Shiyoon. I'm glad.","TWN":"前輩也平安無事，太好了。"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"...응?","JPN":"……あれ？","ENG":"...Hm?","TWN":"……嗯？"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"선배, 되게 기분이 좋아 보이네.","JPN":"先輩、なんだかご機嫌じゃない？","ENG":"Shiyoon, you look really happy.","TWN":"前輩看起來心情很好呢。"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"저요?","JPN":"僕ですか？","ENG":"Me?","TWN":"我嗎？"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"...하하, 그래 보이나요?","JPN":"……ハハ、そう見えますか？","ENG":"...Haha, do I?","TWN":"……哈哈，這麼明顯嗎？"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"응. 늘 웃고 있기야 하지만 지금은 뭔가... 전보다 한결 가벼워진 느낌이랄까.","JPN":"うん。いつも笑ってはいるけど、今は何か……前より一段とスッキリした感じっていうか。","ENG":"Yeah. You're always smiling, but right now it feels like... you seem lighter than before.","TWN":"嗯。雖然你平常都在笑，但現在總覺得……比以前輕鬆多了。"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"호오, 이젠 얼굴만 보고도 무슨 기분인지 아는 사이가 된 거냐?","JPN":"ほう、もう顔を見るだけでどんな気分なのか分かるような仲になったのか？","ENG":"Oh? Have you two gotten close enough to read each other's feelings just by looking at your faces?","TWN":"喔？你們現在已經進展到只看臉就能知道對方心情的關係了嗎？"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"뭐, 뭐가. 그런 거 아니거든?","JPN":"な、何だよ。そんなんじゃないし。","ENG":"W-what are you talking about? It's not like that.","TWN":"什、什麼啊！才不是那樣！"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"다들 잘해주었네.","JPN":"皆、よくやってくれた。","ENG":"You all did well.","TWN":"大家都做得很好。"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L31_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"숱한 고비를 넘겨 마침내, 마왕과 대등하게 싸워볼 기회를 얻었군.","JPN":"幾多の苦難を乗り越え、ついに魔王と対等に戦う機会を手に入れたな。","ENG":"After overcoming so many trials, you've finally earned the chance to fight the Demon Lord on equal footing.","TWN":"歷經那麼多難關，終於得到能和魔王正面交手的機會。"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"그래. 드디어 이 세계를 삼키려 드는 망할 나무뿌리의 근원을 부수러 가는 거야.","JPN":"ああ。ついにこの世界を飲み込もうとしてる憎き木の根の根源を叩きに行くんだ。","ENG":"Yeah. At last, we're going to destroy the source of that damned tree root trying to swallow this world.","TWN":"沒錯。終於可以去摧毀那棵企圖吞噬這個世界的該死樹根源頭了。"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"나아가야 할 좌표는 이미 백 번도 넘게 검증해뒀어. 오차율은 제로에 수렴해.","JPN":"進むべき座標はすでに100回以上検証した。誤差率は0に近い。","ENG":"The coordinates we need to head to have already been verified over a hundred times. The margin of error is practically zero.","TWN":"前進的座標我已經反覆驗證過一百多次，誤差率幾乎等於零。"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"이 좌표는... 우리가 발견했던 청동나무가 있는 곳과 다르군.","JPN":"この座標は……私たちが見つけた青銅の木がある場所ではないな。","ENG":"These coordinates... They're different from where we found the Bronze Tree.","TWN":"這個座標……和我們之前發現青銅樹的地方不一樣。"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"직통으로 길을 여는 건 위험하다고 판단했어. 미확인 에너지가 간섭하고 있거든. 아마도 마왕의 영향력이 직접적으로 닿는 곳이기 때문이겠지.","JPN":"直で道を開くのは危険と判断したんだ。未確認のエネルギーが干渉しているから。おそらく魔王の影響力が直接届いている場所だからだろう。","ENG":"I judged that opening a direct path would be too dangerous. Unidentified energy is interfering. It's probably because it's a place directly under the Demon Lord's influence.","TWN":"我判斷直接開通通道太危險了。那裡有未確認的能量干擾，大概是因為魔王的影響力直接覆蓋到那裡。"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"그래도 이 정도 거리라면 걸어갈 만 하겠네요.","JPN":"でも、この距離なら歩いて行けそうですね。","ENG":"Even so, at this distance, it should be manageable on foot.","TWN":"不過這點距離，走過去也還可以接受。"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"그렇게 걸어갈 동안 마왕이 방해할 거라는 게 문제겠지만-","JPN":"そうやって歩いてるところを、魔王が邪魔してくるってのが問題だけど～","ENG":"The problem is the Demon Lord will likely interfere while we're making our way there...","TWN":"只是走過去的這段時間，魔王肯定會來干擾我們。"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"뭐, 지금으로선 조금 우회해서 가는 게 최선이란 거지?","JPN":"ま、今はちょっと遠回りするのがベストってことよね？","ENG":"Still, for now, taking a slight detour is our best option, right?","TWN":"也就是說，目前稍微繞點路是最好的選擇囉？"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"앗, 저기 하늘 좀 보세요.","JPN":"あっ、あそこの空を見てください。","ENG":"Ah, look up at the sky over there.","TWN":"啊，你們看天空。"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_COMBAT_COFFIN_START"},{"id":"L41_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"차원함선들이잖아?","JPN":"次元艦船？","ENG":"Those are dimensional ships, aren't they?","TWN":"那是次元艦船吧？"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"저게 전부 터널로 들어가는 거야?","JPN":"あれ、全部トンネルに入るの？","ENG":"Are all of them heading into the tunnel?","TWN":"那些全都要進入隧道嗎？"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L43_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"관리국 동원령을 받고 참여한 그라운드 원의 태스크포스들이다.","JPN":"管理局の動員令を受けて参加した、グラウンド・ワンのタスクフォースたちだ。","ENG":"They're the Ground One TASKFORCEs that joined under the Administration's mobilization order.","TWN":"是接到管理局動員令後參與行動的G1特遣勢力。"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L44_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"최고 위험 레벨에 생환 보장할 수 없고, 작전 보수도 제시하지 않았지.","JPN":"最高危険レベルで生還も保証できないし、作戦報酬も明示していないんだがな。","ENG":"It's the highest danger level with no guarantee of survival, and no operational compensation was offered.","TWN":"這次任務是最高危險等級，不保證生還，也沒有提供任何報酬。"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L45_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"그런데도 저만큼이나 모인 거야?","JPN":"それなのにあれだけ集まったの？","ENG":"And even so, that many still gathered?","TWN":"即便如此還來了這麼多人？"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L46_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"다들, 도시를 지켜내느라 바쁜 줄 알았는데.","JPN":"みんな、都市を守ることで忙しいと思ったのに。","ENG":"I thought everyone was busy protecting the city.","TWN":"我還以為大家都忙著守護城市呢。"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L2_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"전선을 사수하는 것도 중요하지만 누군가는 전쟁의 중심지로 가서 이 학살을 끝내야만 해.","JPN":"前線を死守することも大事だが、誰かは戦争の中心地に乗り込み、この虐殺を終わらせないといけない。","ENG":"Holding the front lines is important too, but someone has to head to the heart of the war and put an end to this slaughter.","TWN":"固守前線固然重要，但總得有人前往戰爭的中心，結束這場屠殺。"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L3_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"그 역할을 맡을 자격이, 관리국에게만 있는 건 아니니까.","JPN":"その役割を担当する資格は、管理局に限定されているわけではないからな。","ENG":"And the Administration isn't the only one qualified to take on that role.","TWN":"而有資格擔任這個角色的人，也不只管理局而已。"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L4_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"마왕 타기리온과 사적인 원한 관계로 얽혀 있는 분들도 계실 테고 말이죠.","JPN":"魔王タギリオンに個人的な恨みがある方もいるでしょうしね。","ENG":"Some of them are personally entangled with Demon Lord Thagirion as well.","TWN":"也有人和魔王塔基里翁有私人恩怨吧。"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"대우물 지정 좌표 활성화. 최대 출력 설정을 무시하고 최종 목적지까지 초광역터널을 전개하겠네.","JPN":"大イドの指定座標活性化。最大出力設定を無視し、最終目的地まで超広域トンネルを展開する。","ENG":"Activate the Great Well's designated coordinates. Ignore the maximum output setting and deploy a hyperwide tunnel all the way to the final destination.","TWN":"大井指定座標啟動。無視最大輸出限制，直接展開通往最終目的地的超廣域隧道。"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"출력 과부하 350%...!","JPN":"出力過負荷、350％……！","ENG":"Output overload at 350%...!","TWN":"輸出超載350%……！"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"480%...!","JPN":"480％……！","ENG":"480%...!","TWN":"480%……！"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"1500% 돌파...!","JPN":"1500％を突破……！","ENG":"Passing 1500%...!","TWN":"突破1500%……！"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_SYS_START2"},{"id":"L11_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"...으앗?!","JPN":"……わあっ！？","ENG":"...What?!","TWN":"……欸？！"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"계측기가 용해됐어요. 오버클럭 수치는 측정할 수 없겠네요.","JPN":"計測器が熔解しました。オーバークロックの数値は測定できなさそうですね。","ENG":"The measuring instruments have melted. We can't measure the overclock value anymore.","TWN":"儀器熔化了，已無法測量超頻數值。"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"무시하고 출력을 계속 높이게.","JPN":"無視して出力を上げ続けるのだ。","ENG":"Ignore it and keep increasing the output.","TWN":"不要管，繼續提高輸出。"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"여과기 수복 장치 활성화. 비축된 얼터니움을 전량 투입합니다.","JPN":"ろ過機の修復装置を活性化。備蓄されているオルタニウムを全量投入します。","ENG":"Filter recovery device activated. Deploying all reserved Alternium.","TWN":"啟動修復過濾器裝置，投入所有儲備的替代能量。"},"stage":{"bg":"COUNTERSIDE_WELL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"우물이... 가라앉고 있어. 마치 땅이 녹는 것처럼.","JPN":"イドが……沈んでいってる。まるで地面が溶けているみたいだ。","ENG":"The Well... It's sinking. It's like the ground is melting.","TWN":"井……在下沉，就像地面融化一樣。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"터널이 연결되면서 발생하는 공간 왜곡 현상이야. 눈에는 안 보이지만, 아마 시간축 역시 왜곡되고 있겠지.","JPN":"トンネルが繋がる時に発生する空間歪曲現象だ。目には見えないけど、たぶん時間軸も歪曲しているだろう。","ENG":"It's a spatial distortion phenomenon caused by the tunnel connecting. You can't see it, but the time axis is probably being distorted too.","TWN":"這是隧道連接時產生的空間扭曲現象。雖然肉眼看不見，但時間軸大概也被扭曲了。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"괜찮은 거야? 우물은 타임머신의 본체 같은 거였잖아.","JPN":"大丈夫なの？　イドはタイムマシンの本体みたいなものなのに。","ENG":"Is that okay? The Well was basically the core body of the time machine.","TWN":"沒問題嗎？那口井不是時光機的核心嗎？"},"stage":{"bg":"SKY_RED","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"그 타임머신은 과거로 향하는 출입문을 열면서 제 역할을 다 했어. 다시 쓸 수는 없겠지.","JPN":"そのタイムマシンは過去へ向かう出入口を開けた時点でその役目を終えたんだ。もう使えないだろう。","ENG":"That time machine already fulfilled its role when it opened the gateway to the past. It won't be usable again.","TWN":"那台時光機在打開通往過去的入口時，就已經完成使命了，之後也無法再使用。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"다시 쓸 일도 없을 거야. 증폭터널을 활용할 수 있는 기회는 어차피 한 번이니까.","JPN":"使うこともないはずだよ。増幅トンネルを活用できるチャンスはどうせ一度だけだから。","ENG":"We won't need to use it again anyway. We only had one chance to make use of the amplification tunnel to begin with.","TWN":"而且也不會再有機會用了。利用增幅隧道的機會本來就只有一次。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"꼭 이세계로 가는 거대한 싱크홀 같아요!","JPN":"まるで異世界に通じる巨大なシンクホールみたいです！","ENG":"It looks just like a giant sinkhole leading to another world—isekai!","TWN":"看起來簡直像通往異界的巨大天坑。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"하하, 그건 비유가 아니라 사실 같은데요?","JPN":"ハハ、実際そのようなものですよね。","ENG":"Haha, that doesn't sound like a metaphor. It's basically the truth.","TWN":"哈哈，這不是比喻，根本就是事實吧？"},"stage":{"bg":"SKY_RED","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"이세계물에선 보통 그 세계의 마왕을 해치워야 돌아올 수 있다는 점도 같고요.","JPN":"異世界ものによくある、その世界の魔王をやっつけないと戻れないという設定も一緒ですし。","ENG":"Just like in those isekai novels, where you have to defeat the Demon Lord of that world before you can return.","TWN":"而且也跟異界故事一樣，通常都得打倒那個世界的魔王才能回來。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_RED","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_23"},{"id":"L28_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"초광역터널은 무사히 전개됐네.","JPN":"超広域トンネルは無事展開された。","ENG":"The hyperwide tunnel has been successfully deployed.","TWN":"已經成功展開超廣域隧道。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"시간을 거리로 치환한 만큼, 걸어가는 것보단 차원함선을 이용하는 걸 권장하지.","JPN":"時間を距離に置換した分、歩くよりは次元艦船の利用をおすすめする。","ENG":"Since time has been converted into distance, I recommend using dimensional ships rather than traveling on foot.","TWN":"既然把時間換算成距離了，我建議還是搭次元艦船比較好。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"여과기 멜트다운까지 2.5초, 아슬아슬했네요.","JPN":"ろ過機のメルトダウンまで2.5秒、ギリギリでしたね。","ENG":"2.5 seconds until filter meltdown. That was close.","TWN":"距離過濾器熔毀只剩2.5秒，真驚險。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"케헥...","JPN":"ぐはっ……","ENG":"Gah...","TWN":"咳……"},"stage":{"bg":"SKY_RED","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"이 망할 우물... 내 피를 다 빨아갔어.","JPN":"イドのやつめ……私の血を全部吸い取っていきやがった。","ENG":"This damned Well... it drained all my blood.","TWN":"這該死的井……把我的血都吸光了。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"피가 없어도 살아는 있군.","JPN":"血がなくても死なないんだな。","ENG":"Even without blood, you're still alive.","TWN":"沒有血還能活著啊。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"차라리... 죽여어...","JPN":"いっそ……殺してくれぇ……","ENG":"Just... kill me...","TWN":"還不如……殺了我……"},"stage":{"bg":"SKY_RED","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"그럼 갈까요, 미나 양?","JPN":"では行きましょうか、ミナさん。","ENG":"Shall we go, Mina?","TWN":"那麼我們走吧，米娜？"},"stage":{"bg":"SKY_RED","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"...가자.","JPN":"……行こう。","ENG":"...Let's go.","TWN":"……走吧。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"타기리온을 만나러.","JPN":"タギリオンに会いに。","ENG":"To meet Thagirion.","TWN":"去見塔基里翁。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};